(function(){
  function escapeHtml(s){
    return String(s || '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  function bubbleIcon(){
    return '<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15a4 4 0 0 1-4 4H7l-4 4V7a4 4 0 0 1 4-4h6"/><path d="M17 3h4v4"/><path d="M21 3l-7 7"/></svg>';
  }

  function createStyles(widgetColor){
    var existing = document.getElementById('evo-widget-styles');
    if(existing) existing.remove();
    var css = document.createElement('style');
    css.id = 'evo-widget-styles';
    var color = widgetColor || '#00d4aa';
    css.textContent = "\n      .evo-widget-holder{position:fixed;bottom:88px;right:20px;z-index:2147483000;width:360px;max-width:92vw;height:560px;max-height:80vh;border:0;border-radius:12px;box-shadow:0 10px 30px rgba(0,0,0,.25);overflow:hidden;background:#fff;display:none}\n      .evo-widget-bubble{position:fixed;bottom:20px;right:20px;z-index:2147483001;width:56px;height:56px;border-radius:28px;background:" + color + ";color:#fff;display:flex;align-items:center;justify-content:center;box-shadow:0 8px 20px rgba(0,0,0,.25);cursor:pointer;font-family:system-ui,-apple-system,Segoe UI,Roboto,Ubuntu,Cantarell,Noto Sans,sans-serif;border:none;outline:none}\n      .evo-widget-bubble:hover{opacity:0.9}\n      .evo-widget-iframe{width:100%;height:100%;border:0}\n    ";
    document.head.appendChild(css);
  }

  function ensureHolders(){
    var holder = document.getElementById('evo-widget-holder');
    if(!holder){
      holder = document.createElement('div');
      holder.id = 'evo-widget-holder';
      holder.className = 'evo-widget-holder';
      document.body.appendChild(holder);
    }
    var bubble = document.getElementById('evo-widget-bubble');
    if(!bubble){
      bubble = document.createElement('button');
      bubble.id = 'evo-widget-bubble';
      bubble.className = 'evo-widget-bubble';
      bubble.setAttribute('aria-label','Abrir chat');
      bubble.innerHTML = bubbleIcon();
      document.body.appendChild(bubble);
    }
    var badge = document.getElementById('evo-widget-badge');
    if(!badge){
      badge = document.createElement('span');
      badge.id = 'evo-widget-badge';
      badge.style.cssText = 'position:fixed;bottom:72px;right:12px;background:#ef4444;color:#fff;border-radius:999px;min-width:16px;height:16px;padding:0 5px;font-size:10px;display:none;z-index:2147483002;text-align:center;line-height:16px;';
      badge.textContent = '0';
      document.body.appendChild(badge);
    }
    return { holder: holder, bubble: bubble, badge: badge };
  }

  var __unread = 0;
  function showBadge(){
    try{var b=document.getElementById('evo-widget-badge'); if(b){ b.style.display = __unread>0 ? 'inline-block' : 'none'; b.textContent=String(__unread);} }catch(_){}}
  function playBeep(){
    try{var C=window.AudioContext||window.webkitAudioContext; if(!C) return; var a=new C(); var o=a.createOscillator(); var g=a.createGain(); o.type='sine'; o.frequency.value=880; o.connect(g); g.connect(a.destination); g.gain.setValueAtTime(0.001,a.currentTime); g.gain.exponentialRampToValueAtTime(0.08,a.currentTime+0.01); o.start(); setTimeout(function(){g.gain.exponentialRampToValueAtTime(0.0001,a.currentTime+0.15); o.stop(a.currentTime+0.2);},150);}catch(_){}}

  // Listen messages from iframe (widget) to adjust UI
  window.addEventListener('message', function(e){
    if(typeof e.data !== 'string' || e.data.indexOf('evo-widget:') !== 0) return;
    try{
      var msg = JSON.parse(e.data.replace('evo-widget:',''));
      if(msg && msg.event === 'set-height'){
        var el = document.getElementById('evo-widget-holder');
        if(el){
          var h = Math.max(300, Math.min(640, Number(msg.data && msg.data.height)||560));
          el.style.height = h + 'px';
        }
      } else if (msg && msg.event === 'unread-increment'){
        __unread++; showBadge(); playBeep();
      } else if (msg && msg.event === 'unread-reset'){
        __unread = 0; showBadge();
      } else if (msg && msg.event === 'play-audio'){
        playBeep();
      }
    }catch(_){}
  });

  function open(holder){ holder.style.display = 'block'; }
  function close(holder){ holder.style.display = 'none'; }

  function applyBubblePresentation(bubble, settings){
    var bubbleType = settings && settings.type === 'expanded_bubble' ? 'expanded_bubble' : 'standard';
    var launcherTitle = (settings && settings.launcherTitle) || 'Chat';

    bubble.style.height = '';
    bubble.style.width = '';
    bubble.style.padding = '';
    bubble.style.borderRadius = '';
    bubble.style.gap = '';
    bubble.style.fontWeight = '';
    bubble.style.fontSize = '';
    bubble.style.lineHeight = '';

    if(bubbleType === 'expanded_bubble'){
      bubble.style.height = '48px';
      bubble.style.width = 'auto';
      bubble.style.padding = '0 14px';
      bubble.style.borderRadius = '999px';
      bubble.style.gap = '8px';
      bubble.style.fontWeight = '500';
      bubble.style.fontSize = '14px';
      bubble.style.lineHeight = '1';
      bubble.innerHTML = bubbleIcon() + '<span id="evo-widget-bubble-label">' + escapeHtml(launcherTitle) + '</span>';
    } else {
      bubble.innerHTML = bubbleIcon();
    }
  }

  function postToIframe(ev){
    try{
      var ifr=document.getElementById('evo-widget-iframe');
      if(ifr&&ifr.contentWindow){
        ifr.contentWindow.postMessage('evo-widget:'+JSON.stringify(ev),'*');
      }
    }catch(e){}
  }

  function initIframe(holder, baseUrl, websiteToken, settings){
    var iframe = document.getElementById('evo-widget-iframe');
    var params = 'website_token=' + encodeURIComponent(websiteToken || '');
    if(settings && settings.apiBase){ params += '&api_base=' + encodeURIComponent(settings.apiBase); }
    var src = (baseUrl || '') + '/widget?' + params;
    if(!iframe){
      iframe = document.createElement('iframe');
      iframe.id = 'evo-widget-iframe';
      iframe.className = 'evo-widget-iframe';
      iframe.allow = 'camera;microphone;fullscreen;picture-in-picture;clipboard-write;';
      holder.appendChild(iframe);
    }
    iframe.onload=function(){
      postToIframe({event:'config-set', settings: settings || {}});
    };
    iframe.src = src;
  }

  window.evoChatSDK = window.evoChatSDK || {
    run: function(opts){
      try{
        var settings = window.evoChatSettings || {};
        var widgetColor = (settings && settings.widgetColor) || '#00d4aa';
        createStyles(widgetColor);
        var baseUrl = (opts && opts.baseUrl) || '';
        var token = (opts && opts.websiteToken) || '';
        var pos = settings.position === 'left' ? 'left' : 'right';

        var nodes = ensureHolders();
        applyBubblePresentation(nodes.bubble, settings);
        // Position bubble/holder
        if(pos === 'left'){
          nodes.holder.style.right = '';
          nodes.holder.style.left = '20px';
          nodes.bubble.style.right = '';
          nodes.bubble.style.left = '20px';
          nodes.badge.style.right = '';
          nodes.badge.style.left = '12px';
        } else {
          nodes.holder.style.left = '';
          nodes.holder.style.right = '20px';
          nodes.bubble.style.left = '';
          nodes.bubble.style.right = '20px';
          nodes.badge.style.left = '';
          nodes.badge.style.right = '12px';
        }

        initIframe(nodes.holder, baseUrl, token, settings);

        var isOpen = false;
        nodes.bubble.onclick = function(){
          isOpen = !isOpen;
          if(isOpen) open(nodes.holder); else close(nodes.holder);
          postToIframe({event:'toggle-open', isOpen:isOpen});
        };

        // Expose helpers
        window.evoChatSDK.toggle=function(state){
          if(state==='open'){ isOpen=true; open(nodes.holder);}
          else if(state==='close'){ isOpen=false; close(nodes.holder);}
          else { isOpen=!isOpen; if(isOpen) open(nodes.holder); else close(nodes.holder);}
          postToIframe({event:'toggle-open', isOpen:isOpen});
        };
        window.evoChatSDK.setUser=function(identifier, user){
          postToIframe({event:'set-user', identifier:identifier, user:user});
        };
        window.evoChatSDK.setCustomAttributes=function(custom){
          postToIframe({event:'set-custom-attributes', custom:custom});
        };
      }catch(e){
        console && console.warn && console.warn('evoChatSDK error', e);
      }
    }
  };
})();
